from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Use the first subject as the main subject
    main_subject = list(subject_map.keys())[0] if subject_map else ""
    sentence = main_subject

    # Track different types of information for better sentence structure
    location_info = []
    elevation_info = []
    runway_info = []
    identifier_info = []
    other_info = []

    for subject, triples in subject_map.items():
        for predicate, obj in triples:
            if predicate == "cityServed":
                other_info.append(f"serves the city of {obj}")
            elif predicate == "mayor":
                other_info.append(f"has a mayor of {obj}")
            elif predicate == "isPartOf":
                location_info.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                other_info.append(f"is operated by {obj}")
            elif predicate == "location":
                location_info.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                elevation_info.append(f"has an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                other_info.append(f"has a runway length of {obj} metres")
            elif predicate == "country":
                location_info.append(f"is located in {obj}")
            elif predicate == "capital":
                other_info.append(f"has {obj} as its capital")
            elif predicate == "language":
                other_info.append(f"where {obj} is spoken")
            elif predicate == "leader":
                other_info.append(f"is led by {obj}")
            elif predicate == "owner":
                other_info.append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                runway_info.append(f"has a first runway of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                runway_info.append(f"has a first runway surface type of {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                runway_info.append(f"has a third runway of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                identifier_info.append(f"has an ICAO location identifier of {obj}")
            elif predicate == "locationIdentifier":
                identifier_info.append(f"has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                elevation_info.append(f"has an elevation of {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                identifier_info.append(f"has an IATA location identifier of {obj}")
            elif predicate == "nativeName":
                other_info.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                other_info.append(f"has a leader party of {obj}")
            elif predicate == "runwaySurfaceType":
                other_info.append(f"has a runway surface type of {obj}")
            elif predicate == "1stRunwayNumber":
                other_info.append(f"has a first runway numbered {obj}")
            elif predicate == "runwayName":
                other_info.append(f"has a runway named {obj}")
            elif predicate == "elevationAboveTheSeaLevelInMetres":
                elevation_info.append(f"has an elevation of {obj} metres above sea level")
            else:
                # For any other predicate, use a more natural construction
                if predicate.endswith("LengthFeet") or predicate.endswith("LengthMetre"):
                    other_info.append(f"has a {predicate.replace('LengthFeet', 'length').replace('LengthMetre', 'length')} of {obj}")
                elif predicate.endswith("SurfaceType"):
                    other_info.append(f"has a {predicate.replace('SurfaceType', 'surface type')} of {obj}")
                elif predicate.endswith("Number"):
                    other_info.append(f"has a {predicate.replace('Number', 'number')} of {obj}")
                elif predicate.endswith("Identifier"):
                    identifier_info.append(f"has a {predicate.replace('Identifier', 'identifier')} of {obj}")
                else:
                    # Use possessive form or "is" construction for better fluency
                    if predicate == "country" or predicate == "location":
                        other_info.append(f"is in {obj}")
                    elif predicate == "elevationAboveTheSeaLevel" or predicate == "elevationAboveTheSeaLevelInFeet" or predicate == "elevationAboveTheSeaLevelInMetres":
                        other_info.append(f"is at an elevation of {obj}")
                    else:
                        # Use "is" for simple attributes
                        if obj.startswith('"') and obj.endswith('"'):
                            obj = obj[1:-1]  # Remove quotes
                        other_info.append(f"is {obj}")

    # Build the sentence with better structure
    if location_info:
        sentence += " " + ", ".join(location_info)
    if elevation_info:
        if sentence and not sentence.endswith(" "):
            sentence += " "
        sentence += ", ".join(elevation_info)
    if runway_info:
        if sentence and not sentence.endswith(" "):
            sentence += " "
        sentence += ", ".join(runway_info)
    if identifier_info:
        if sentence and not sentence.endswith(" "):
            sentence += " "
        sentence += ", ".join(identifier_info)
    if other_info:
        if sentence and not sentence.endswith(" "):
            sentence += " and "
        sentence += ", ".join(other_info)

    return sentence + "."
